var e=[{id:`L2_1`,type:`dialog`,speaker:`COMMANDER_REPLACER_NULL_NULL`,text:{KOREA:`퇴, 퇴각!`,JPN:`た、退却！`,ENG:`F-fall back!`,TWN:`撤、撤退！`},stage:{bg:`COUNTERSIDE_PLAIN`,slots:{L:null,C:{char_id:`COMMANDER_REPLACER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`COMMANDER_REPLACER_NULL_NULL`,text:{KOREA:`퇴각하라!!`,JPN:`退却せよ！！`,ENG:`Fall back!`,TWN:`快撤退！`},stage:{bg:`COUNTERSIDE_PLAIN`,slots:{L:null,C:{char_id:`COMMANDER_REPLACER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`SOLDIER_REPLACER_NULL_NULL`,text:{KOREA:`퇴각로가 막혔는데 어디로 퇴각합니까?!`,JPN:`退却路が遮断されたのに、どこに退却すれば！？`,ENG:`But where to? Our retreat route is occupied by the enemy!`,TWN:`退路被敵人切斷了，要撤退到哪啊？！`},stage:{bg:`COUNTERSIDE_PLAIN`,slots:{L:{char_id:`COMMANDER_REPLACER_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`SOLDIER_REPLACER_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L7_1`,type:`dialog`,speaker:`COMMANDER_REPLACER_NULL_NULL`,text:{KOREA:`아, 알 게 뭐야! 후방이 안되면 전방으로 퇴각해!!`,JPN:`し、知るか！　後方がダメなら、前方に退却しろ！！`,ENG:`I-I don't know, fall back to the front then!`,TWN:`啊，你又知道什麼了！後方不能撤退，那就往前方撤退！`},stage:{bg:`COUNTERSIDE_PLAIN`,slots:{L:{char_id:`COMMANDER_REPLACER_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`SOLDIER_REPLACER_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L10_1`,type:`dialog`,speaker:`SOLDIER_REPLACER_NULL_NULL`,text:{KOREA:`아니, 지휘관님! 그게 무슨......!!`,JPN:`え、指揮官！　それはどういう……！！`,ENG:`Come again, Commander? How do you call that falling back?`,TWN:`呃，指揮官！這怎麼……！`},stage:{bg:`COUNTERSIDE_PLAIN`,slots:{L:null,C:{char_id:`SOLDIER_REPLACER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NULL_NULL`,text:{KOREA:`어, 어떻게 된 거야......`,JPN:`ど、どういうこと……`,ENG:`W-what happened?`,TWN:`怎、怎麼回事啊……`},stage:{bg:`COUNTERSIDE_PLAIN`,slots:{L:null,C:{char_id:`YOOMINA_FENRIR_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NULL_NULL`,text:{KOREA:`내가 이렇게 강했나?`,JPN:`私、こんなに強かったっけ？`,ENG:`Have I always been this strong?`,TWN:`我有這麼強嗎？`},stage:{bg:`COUNTERSIDE_PLAIN`,slots:{L:null,C:{char_id:`YOOMINA_FENRIR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NULL_NULL`,text:{KOREA:`아니면 이게...... 클리포트 인자의 힘......`,JPN:`それとも、これが……クリフォト・ファクターの力……`,ENG:`Or... this is probably the true power of the Qliphoth Factor...`,TWN:`還是這是……逆卡巴拉因子的力量……`},stage:{bg:`COUNTERSIDE_PLAIN`,slots:{L:null,C:{char_id:`YOOMINA_FENRIR_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`YOOJIN_ALT_NULL_NULL`,text:{KOREA:`야! 아직도 준비 중이냐? 저 자식들 떼로 몰려온다고!`,JPN:`おい！　まだ準備中かよ？　あいつら束になって押し寄せてくるぜ！`,ENG:`Hey! How long until you're done? They're coming! In droves!`,TWN:`喂！還在準備嗎？那些傢伙們已經衝過來了！`},stage:{bg:`COUNTERSIDE_PLAIN`,slots:{L:{char_id:`KIMSOBIN_ALT_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`YOOJIN_ALT_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L19_1`,type:`dialog`,speaker:`KIMSOBIN_ALT_NULL_NULL`,text:{KOREA:`이, 이제 끝났어......!`,JPN:`も、もう終わったよ……！`,ENG:`I-I'm done now!`,TWN:`已、已經好了……！`},stage:{bg:`COUNTERSIDE_PLAIN`,slots:{L:{char_id:`KIMSOBIN_ALT_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`YOOJIN_ALT_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L20_1`,type:`dialog`,speaker:`KIMSOBIN_ALT_NULL_NULL`,text:{KOREA:`쏘, 쏩니다! 다들 조심하세요!`,JPN:`う、撃つよ！　みんな、気を付けて！`,ENG:`I-I'm firing! Watch out, everyone!`,TWN:`開、開炮！大家小心！`},stage:{bg:`COUNTERSIDE_PLAIN`,slots:{L:{char_id:`KIMSOBIN_ALT_NULL_NULL`,face:`UNIT_SERIOUS`},C:null,R:{char_id:`YOOJIN_ALT_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L22_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NULL_NULL`,text:{KOREA:`저건......?`,JPN:`あれは……？`,ENG:`What the...`,TWN:`那是……？`},stage:{bg:`COUNTERSIDE_PLAIN`,slots:{L:null,C:{char_id:`YOOMINA_FENRIR_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L39_1`,type:`dialog`,speaker:`YOOJIN_ALT_NULL_NULL`,text:{KOREA:`콜록! 콜록!`,JPN:`ゴホゴホ！`,ENG:`*Cough, cough*`,TWN:`咳咳！咳咳！`},stage:{bg:`COUNTERSIDE_PLAIN`,slots:{L:null,C:{char_id:`YOOJIN_ALT_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L40_1`,type:`dialog`,speaker:`YOOJIN_ALT_NULL_NULL`,text:{KOREA:`끄, 끝났어?`,JPN:`お、終わったか？`,ENG:`I-is it over?`,TWN:`結、結束了嗎？`},stage:{bg:`COUNTERSIDE_PLAIN`,slots:{L:null,C:{char_id:`YOOJIN_ALT_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L43_1`,type:`dialog`,speaker:`XIAOLIN_ALT_NULL_NULL`,text:{KOREA:`......적 병력 궤멸 확인.`,JPN:`……敵兵力の壊滅を確認。`,ENG:`Enemy elimination confirmed.`,TWN:`……確認消滅敵方兵力。`},stage:{bg:`COUNTERSIDE_PLAIN`,slots:{L:{char_id:`YOOJIN_ALT_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`XIAOLIN_ALT_NULL_NULL`,face:`UNIT_IDLE`}}}}];export{e as default};